     1→'use strict';
     2→
     3→const MarkdownParser = (() => {
     4→  // 이스케이프 처리를 위한 플레이스홀더 센티넬 문자 (일반 텍스트에 거의 등장하지 않음)
     5→  const PH_START = '\x02';
     6→  const PH_END = '\x03';
     7→
     8→  function escapeHtml(str) {
     9→    return str
    10→      .replace(/&/g, '&amp;')
    11→      .replace(/</g, '&lt;')
    12→      .replace(/>/g, '&gt;')
    13→      .replace(/"/g, '&quot;');
    14→  }
    15→
    16→  function storePlaceholder(arr, value) {
    17→    arr.push(value);
    18→    return `${PH_START}${arr.length - 1}${PH_END}`;
    19→  }
    20→
    21→  function restorePlaceholders(text, arr) {
    22→    return text.replace(
    23→      new RegExp(`${PH_START}(\\d+)${PH_END}`, 'g'),
    24→      (_, i) => arr[+i]
    25→    );
    26→  }
    27→
    28→  // 인라인 요소 파싱: 이스케이프, 코드, 이미지, 링크, 강조, 줄바꿈
    29→  function parseInline(text) {
    30→    const ph = [];
    31→
    32→    // 1. 이스케이프 문자를 먼저 처리해야 \` 가 코드 구분자로 인식되지 않음
    33→    text = text.replace(/\\([\\`*_{}\[\]()#+\-.!|~])/g, (_, ch) =>
    34→      storePlaceholder(ph, escapeHtml(ch))
    35→    );
    36→
    37→    // 2. 인라인 코드 추출 (이스케이프 처리 후 → 보호된 백틱은 코드 구분자로 사용 안 됨)
    38→    text = text.replace(/`([^`]+)`/g, (_, code) =>
    39→      storePlaceholder(ph, `<code>${escapeHtml(code)}</code>`)
    40→    );
    41→
    42→    // 3. 남은 원시 텍스트의 HTML 특수문자 이스케이프 (XSS 방지)
    43→    //    코드·이스케이프는 이미 플레이스홀더로 보호되어 영향 없음
    44→    text = text.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
    45→
    46→    // 이미지 (링크보다 먼저 처리)
    47→    text = text.replace(/!\[([^\]]*)\]\(([^)]+)\)/g, (_, alt, raw) => {
    48→      const m = raw.match(/^(.+?)(?:\s+"([^"]+)")?$/);
    49→      const src = m[1].trim();
    50→      const title = m[2] ? ` title="${escapeHtml(m[2])}"` : '';
    51→      return storePlaceholder(ph,
    52→        `<img src="${escapeHtml(src)}" alt="${escapeHtml(alt)}"${title}>`
    53→      );
    54→    });
    55→
    56→    // 링크
    57→    text = text.replace(/\[([^\]]+)\]\(([^)]+)\)/g, (_, label, raw) => {
    58→      const m = raw.match(/^(.+?)(?:\s+"([^"]+)")?$/);
    59→      const href = m[1].trim();
    60→      const title = m[2] ? ` title="${escapeHtml(m[2])}"` : '';
    61→      return storePlaceholder(ph,
    62→        `<a href="${escapeHtml(href)}"${title}>${label}</a>`
    63→      );
    64→    });
    65→
    66→    // 굵은 이탤릭 (*** 또는 ___)
    67→    text = text.replace(/\*{3}(.+?)\*{3}/g, '<strong><em>$1</em></strong>');
    68→    text = text.replace(/_{3}(.+?)_{3}/g, '<strong><em>$1</em></strong>');
    69→
    70→    // 굵게 (** 또는 __)
    71→    text = text.replace(/\*{2}(.+?)\*{2}/g, '<strong>$1</strong>');
    72→    text = text.replace(/_{2}(.+?)_{2}/g, '<strong>$1</strong>');
    73→
    74→    // 이탤릭 (* 또는 _)
    75→    text = text.replace(/\*([^*\n]+)\*/g, '<em>$1</em>');
    76→    text = text.replace(/_([^_\n]+)_/g, '<em>$1</em>');
    77→
    78→    // 플레이스홀더 복원
    79→    text = restorePlaceholders(text, ph);
    80→
    81→    // 하드 줄바꿈 (행 끝 공백 2개 이상)
    82→    text = text.replace(/  $/gm, '<br>');
    83→
    84→    return text;
    85→  }
    86→
    87→  function getIndent(line) {
    88→    const m = line.match(/^(\s*)/);
    89→    return m ? m[1].length : 0;
    90→  }
    91→
    92→  function isListItem(line) {
    93→    return /^\s*([-*+]|\d+\.)\s/.test(line);
    94→  }
    95→
    96→  // 리스트 블록 재귀 파싱 (중첩 지원)
    97→  function parseList(lines, startIdx, baseIndent, ordered) {
    98→    const tag = ordered ? 'ol' : 'ul';
    99→    let html = `<${tag}>\n`;
   100→    let i = startIdx;
   101→
   102→    while (i < lines.length) {
   103→      const line = lines[i];
   104→
   105→      // 빈 줄: 다음 줄이 리스트를 이어가면 계속, 아니면 종료
   106→      if (line.trim() === '') {
   107→        if (i + 1 < lines.length && isListItem(lines[i + 1]) &&
   108→            getIndent(lines[i + 1]) >= baseIndent) {
   109→          i++;
   110→          continue;
   111→        }
   112→        break;
   113→      }
   114→
   115→      if (!isListItem(line)) break;
   116→
   117→      const indent = getIndent(line);
   118→      if (indent < baseIndent) break;
   119→      if (indent > baseIndent) { i++; continue; } // 예상치 못한 깊은 들여쓰기 건너뜀
   120→
   121→      const itemMatch = ordered
   122→        ? line.match(/^\s*\d+\.\s+(.*)/)
   123→        : line.match(/^\s*[-*+]\s+(.*)/);
   124→
   125→      if (!itemMatch) { i++; continue; }
   126→
   127→      const itemText = itemMatch[1];
   128→      i++;
   129→
   130→      // 중첩 리스트 확인
   131→      let nestedHtml = '';
   132→      if (i < lines.length && isListItem(lines[i])) {
   133→        const nestedIndent = getIndent(lines[i]);
   134→        if (nestedIndent > indent) {
   135→          const nestedOrdered = /^\s*\d+\./.test(lines[i]);
   136→          const result = parseList(lines, i, nestedIndent, nestedOrdered);
   137→          nestedHtml = '\n' + result.html;
   138→          i = result.nextIdx;
   139→        }
   140→      }
   141→
   142→      html += `  <li>${parseInline(itemText)}${nestedHtml}</li>\n`;
   143→    }
   144→
   145→    html += `</${tag}>\n`;
   146→    return { html, nextIdx: i };
   147→  }
   148→
   149→  // 블록 요소 파싱 (재귀 지원: blockquote 내부 처리)
   150→  function parseBlocks(markdown) {
   151→    const lines = markdown.split('\n');
   152→    let html = '';
   153→    let i = 0;
   154→
   155→    while (i < lines.length) {
   156→      const line = lines[i];
   157→
   158→      // 펜스드 코드 블록 (``` 또는 ~~~)
   159→      const fenceMatch = line.match(/^(`{3,}|~{3,})(.*)/);
   160→      if (fenceMatch) {
   161→        const fenceChar = fenceMatch[1][0];
   162→        const fenceLen = fenceMatch[1].length;
   163→        const lang = fenceMatch[2].trim();
   164→        const codeLines = [];
   165→        i++;
   166→        while (i < lines.length) {
   167→          const closingMatch = lines[i].match(/^(`{3,}|~{3,})\s*$/);
   168→          if (closingMatch && closingMatch[1][0] === fenceChar &&
   169→              closingMatch[1].length >= fenceLen) break;
   170→          codeLines.push(lines[i]);
   171→          i++;
   172→        }
   173→        i++; // 닫는 펜스 건너뜀
   174→        const langClass = lang ? ` class="language-${escapeHtml(lang)}"` : '';
   175→        const langLabel = lang
   176→          ? `<div class="code-lang-label">${escapeHtml(lang)}</div>`
   177→          : '';
   178→        html += `<pre class="code-block">${langLabel}<code${langClass}>${escapeHtml(codeLines.join('\n'))}</code></pre>\n`;
   179→        continue;
   180→      }
   181→
   182→      // ATX 제목 (# ~ ######)
   183→      const headingMatch = line.match(/^(#{1,6})\s+(.*?)(?:\s+#+\s*)?$/);
   184→      if (headingMatch) {
   185→        const level = headingMatch[1].length;
   186→        html += `<h${level}>${parseInline(headingMatch[2].trim())}</h${level}>\n`;
   187→        i++;
   188→        continue;
   189→      }
   190→
   191→      // 수평선 (---, ***, ___)
   192→      if (/^(\*\s*){3,}$|^(-\s*){3,}$|^(_\s*){3,}$/.test(line.trim())) {
   193→        html += '<hr>\n';
   194→        i++;
   195→        continue;
   196→      }
   197→
   198→      // 인용 블록
   199→      if (line.startsWith('>')) {
   200→        const quoteLines = [];
   201→        while (i < lines.length) {
   202→          const l = lines[i];
   203→          if (l.startsWith('>')) {
   204→            quoteLines.push(l.replace(/^>\s?/, ''));
   205→            i++;
   206→          } else if (l.trim() === '') {
   207→            // 빈 줄은 다음 줄이 인용을 이어가는 경우만 포함
   208→            if (i + 1 < lines.length && lines[i + 1].startsWith('>')) {
   209→              quoteLines.push('');
   210→              i++;
   211→            } else {
   212→              break;
   213→            }
   214→          } else {
   215→            break;
   216→          }
   217→        }
   218→        html += `<blockquote>\n${parseBlocks(quoteLines.join('\n'))}</blockquote>\n`;
   219→        continue;
   220→      }
   221→
   222→      // 비순서 / 순서 리스트
   223→      if (/^\s*([-*+])\s/.test(line) || /^\s*\d+\.\s/.test(line)) {
   224→        const indent = getIndent(line);
   225→        const ordered = /^\s*\d+\./.test(line);
   226→        const result = parseList(lines, i, indent, ordered);
   227→        html += result.html;
   228→        i = result.nextIdx;
   229→        continue;
   230→      }
   231→
   232→      // 빈 줄 건너뜀
   233→      if (line.trim() === '') {
   234→        i++;
   235→        continue;
   236→      }
   237→
   238→      // 단락: 블록 요소가 아닌 연속 줄을 묶음
   239→      const paraLines = [];
   240→      while (i < lines.length) {
   241→        const l = lines[i];
   242→        if (l.trim() === '') break;
   243→        if (/^#{1,6}\s/.test(l)) break;
   244→        if (/^(`{3,}|~{3,})/.test(l)) break;
   245→        if (/^>/.test(l)) break;
   246→        if (/^(\*\s*){3,}$|^(-\s*){3,}$|^(_\s*){3,}$/.test(l.trim())) break;
   247→        if (/^\s*([-*+])\s/.test(l) || /^\s*\d+\.\s/.test(l)) break;
   248→        paraLines.push(l);
   249→        i++;
   250→      }
   251→
   252→      if (paraLines.length > 0) {
   253→        // 행 내부 하드 줄바꿈(공백 2개) 처리
   254→        const parts = paraLines.map((l, idx) => {
   255→          if (idx < paraLines.length - 1 && /  $/.test(l)) {
   256→            return parseInline(l.replace(/\s+$/, '')) + '<br>';
   257→          }
   258→          return parseInline(l);
   259→        });
   260→        html += `<p>${parts.join('\n')}</p>\n`;
   261→      }
   262→    }
   263→
   264→    return html;
   265→  }
   266→
   267→  return { parse: parseBlocks };
   268→})();
   269→
   270→// Node.js 환경에서 모듈로 내보내기
   271→if (typeof module !== 'undefined') module.exports = MarkdownParser;
   272→

