     1→'use strict';
     2→
     3→const STORAGE_KEY = 'md-editor-content';
     4→const SAVE_DEBOUNCE_MS = 400;
     5→
     6→// 기본 샘플 마크다운
     7→const DEFAULT_CONTENT = `# Markdown Editor에 오신 것을 환영합니다
     8→
     9→**실시간 미리보기**가 있는 마크다운 편집기입니다. *왼쪽*에서 작성하고 *오른쪽*에서 결과를 확인하세요.
    10→
    11→## 텍스트 강조
    12→
    13→**굵게**, *이탤릭*, ***굵은 이탤릭*** 모두 지원합니다.
    14→
    15→인라인 \`코드\`와 [링크](https://example.com)도 사용할 수 있습니다.
    16→
    17→## 코드 블록
    18→
    19→\`\`\`javascript
    20→// 피보나치 수열
    21→function fibonacci(n) {
    22→  if (n <= 1) return n;
    23→  return fibonacci(n - 1) + fibonacci(n - 2);
    24→}
    25→
    26→console.log(fibonacci(10)); // 55
    27→\`\`\`
    28→
    29→## 리스트
    30→
    31→### 비순서 목록
    32→- 항목 하나
    33→- 항목 둘
    34→  - 중첩 항목 A
    35→  - 중첩 항목 B
    36→- 항목 셋
    37→
    38→### 순서 목록
    39→1. 첫 번째 단계
    40→2. 두 번째 단계
    41→3. 세 번째 단계
    42→
    43→## 인용 블록
    44→
    45→> 마크다운은 간단한 문법으로
    46→> 서식 있는 문서를 만들 수 있습니다.
    47→>
    48→> > 중첩 인용도 지원합니다.
    49→
    50→## 수평선
    51→
    52→---
    53→
    54→*이제 직접 편집해 보세요!*
    55→`;
    56→
    57→let editor, preview, resizer, editorPane, previewPane;
    58→let saveTimer = null;
    59→let isResizing = false;
    60→let resizeStartX = 0;
    61→let resizeStartEditorWidth = 0;
    62→let resizeStartPreviewWidth = 0;
    63→
    64→// ─── 미리보기 갱신 ────────────────────────────────────────────────────────────
    65→
    66→function updatePreview() {
    67→  const html = MarkdownParser.parse(editor.value);
    68→  preview.innerHTML = html;
    69→}
    70→
    71→// ─── localStorage 저장/복원 ───────────────────────────────────────────────────
    72→
    73→function scheduleAutoSave() {
    74→  clearTimeout(saveTimer);
    75→  saveTimer = setTimeout(() => {
    76→    try {
    77→      localStorage.setItem(STORAGE_KEY, editor.value);
    78→    } catch (e) {
    79→      // 스토리지 용량 초과 등의 오류는 조용히 무시
    80→    }
    81→  }, SAVE_DEBOUNCE_MS);
    82→}
    83→
    84→function loadFromStorage() {
    85→  try {
    86→    const saved = localStorage.getItem(STORAGE_KEY);
    87→    editor.value = (saved !== null) ? saved : DEFAULT_CONTENT;
    88→  } catch (e) {
    89→    editor.value = DEFAULT_CONTENT;
    90→  }
    91→}
    92→
    93→// ─── 커서 위치에 텍스트 삽입 ─────────────────────────────────────────────────
    94→
    95→/**
    96→ * 선택 영역을 before/after로 감싸거나, 선택이 없으면 placeholder를 삽입한다.
    97→ * @param {string} before  - 앞에 삽입할 마크다운
    98→ * @param {string} after   - 뒤에 삽입할 마크다운
    99→ * @param {string} placeholder - 선택이 없을 때 사용할 기본 텍스트
   100→ */
   101→function insertInline(before, after = '', placeholder = '') {
   102→  const start = editor.selectionStart;
   103→  const end = editor.selectionEnd;
   104→  const text = editor.value;
   105→  const selected = text.substring(start, end);
   106→
   107→  const content = selected || placeholder;
   108→  const insertion = `${before}${content}${after}`;
   109→
   110→  editor.value = text.substring(0, start) + insertion + text.substring(end);
   111→
   112→  if (selected) {
   113→    editor.selectionStart = start;
   114→    editor.selectionEnd = start + insertion.length;
   115→  } else {
   116→    editor.selectionStart = start + before.length;
   117→    editor.selectionEnd = start + before.length + placeholder.length;
   118→  }
   119→
   120→  commitEdit();
   121→}
   122→
   123→/**
   124→ * 현재 줄의 앞에 prefix를 추가한다.
   125→ * 이미 동일한 prefix가 있으면 제거한다(토글).
   126→ * @param {string} prefix
   127→ */
   128→function insertLinePrefix(prefix) {
   129→  const start = editor.selectionStart;
   130→  const end = editor.selectionEnd;
   131→  const text = editor.value;
   132→
   133→  const lineStart = text.lastIndexOf('\n', start - 1) + 1;
   134→  const lineEnd = (() => {
   135→    const idx = text.indexOf('\n', end);
   136→    return idx === -1 ? text.length : idx;
   137→  })();
   138→
   139→  const currentLine = text.substring(lineStart, lineEnd);
   140→
   141→  let newLine, delta;
   142→  if (currentLine.startsWith(prefix)) {
   143→    newLine = currentLine.substring(prefix.length);
   144→    delta = -prefix.length;
   145→  } else {
   146→    newLine = prefix + currentLine;
   147→    delta = prefix.length;
   148→  }
   149→
   150→  editor.value = text.substring(0, lineStart) + newLine + text.substring(lineEnd);
   151→  editor.selectionStart = Math.max(lineStart, start + delta);
   152→  editor.selectionEnd = Math.max(lineStart, end + delta);
   153→
   154→  commitEdit();
   155→}
   156→
   157→/** 현재 줄에 제목 마크다운을 삽입한다. 기존 제목 prefix는 교체한다. */
   158→function insertHeading(level) {
   159→  const prefix = '#'.repeat(level) + ' ';
   160→  const start = editor.selectionStart;
   161→  const end = editor.selectionEnd;
   162→  const text = editor.value;
   163→
   164→  const lineStart = text.lastIndexOf('\n', start - 1) + 1;
   165→  const lineEnd = (() => {
   166→    const idx = text.indexOf('\n', end);
   167→    return idx === -1 ? text.length : idx;
   168→  })();
   169→
   170→  const currentLine = text.substring(lineStart, lineEnd);
   171→  // 기존 제목 prefix 제거 후 새 prefix 추가
   172→  const stripped = currentLine.replace(/^#{1,6}\s/, '');
   173→  const newLine = prefix + stripped;
   174→
   175→  editor.value = text.substring(0, lineStart) + newLine + text.substring(lineEnd);
   176→  editor.selectionStart = lineStart + newLine.length;
   177→  editor.selectionEnd = lineStart + newLine.length;
   178→
   179→  commitEdit();
   180→}
   181→
   182→/** 링크 삽입: 선택 텍스트는 링크 레이블로, url 부분에 커서를 위치시킨다. */
   183→function insertLink() {
   184→  const start = editor.selectionStart;
   185→  const end = editor.selectionEnd;
   186→  const text = editor.value;
   187→  const selected = text.substring(start, end);
   188→
   189→  const label = selected || '링크 텍스트';
   190→  const insertion = `[${label}](url)`;
   191→
   192→  editor.value = text.substring(0, start) + insertion + text.substring(end);
   193→
   194→  // 'url' 부분 선택
   195→  const urlStart = start + label.length + 3; // "[label](" 이후
   196→  editor.selectionStart = urlStart;
   197→  editor.selectionEnd = urlStart + 3; // 'url' 길이 3
   198→
   199→  commitEdit();
   200→}
   201→
   202→/** 이미지 삽입 */
   203→function insertImage() {
   204→  const start = editor.selectionStart;
   205→  const end = editor.selectionEnd;
   206→  const text = editor.value;
   207→  const selected = text.substring(start, end);
   208→
   209→  const alt = selected || '이미지 설명';
   210→  const insertion = `![${alt}](image-url)`;
   211→
   212→  editor.value = text.substring(0, start) + insertion + text.substring(end);
   213→
   214→  // 'image-url' 부분 선택
   215→  const urlStart = start + alt.length + 4; // "![alt](" 이후
   216→  const urlPlaceholder = 'image-url';
   217→  editor.selectionStart = urlStart;
   218→  editor.selectionEnd = urlStart + urlPlaceholder.length;
   219→
   220→  commitEdit();
   221→}
   222→
   223→/** 코드 블록 삽입: 선택된 텍스트는 블록 안으로 */
   224→function insertCodeBlock() {
   225→  const start = editor.selectionStart;
   226→  const end = editor.selectionEnd;
   227→  const text = editor.value;
   228→  const selected = text.substring(start, end);
   229→
   230→  // 앞에 빈 줄 확보
   231→  const needsLeadingNewline = start > 0 && text[start - 1] !== '\n';
   232→  const leading = needsLeadingNewline ? '\n' : '';
   233→
   234→  const insertion = `${leading}\`\`\`\n${selected || '코드를 입력하세요'}\n\`\`\`\n`;
   235→  editor.value = text.substring(0, start) + insertion + text.substring(end);
   236→
   237→  if (selected) {
   238→    editor.selectionStart = start + leading.length + 4;
   239→    editor.selectionEnd = start + leading.length + 4 + selected.length;
   240→  } else {
   241→    const codeStart = start + leading.length + 4;
   242→    editor.selectionStart = codeStart;
   243→    editor.selectionEnd = codeStart + '코드를 입력하세요'.length;
   244→  }
   245→
   246→  commitEdit();
   247→}
   248→
   249→/** 수평선 삽입 */
   250→function insertHR() {
   251→  const start = editor.selectionStart;
   252→  const text = editor.value;
   253→
   254→  const needsLeadingNewline = start > 0 && text[start - 1] !== '\n';
   255→  const insertion = (needsLeadingNewline ? '\n' : '') + '\n---\n\n';
   256→
   257→  editor.value = text.substring(0, start) + insertion + text.substring(start);
   258→  editor.selectionStart = start + insertion.length;
   259→  editor.selectionEnd = start + insertion.length;
   260→
   261→  commitEdit();
   262→}
