   288→function handleToolbarClick(e) {
   289→  const btn = e.target.closest('[data-action]');
   290→  if (!btn) return;
   291→  const action = btn.dataset.action;
   292→  if (TOOLBAR_ACTIONS[action]) {
   293→    TOOLBAR_ACTIONS[action]();
   294→  }
