   299→function handleKeydown(e) {
   300→  if (!e.ctrlKey && !e.metaKey) return;
   301→
   302→  switch (e.key.toLowerCase()) {
   303→    case 'b':
   304→      e.preventDefault();
   305→      TOOLBAR_ACTIONS.bold();
   306→      break;
   307→    case 'i':
   308→      e.preventDefault();
   309→      TOOLBAR_ACTIONS.italic();
   310→      break;
   311→    case 'k':
   312→      e.preventDefault();
   313→      TOOLBAR_ACTIONS.link();
   314→      break;
   315→    default:
   316→      break;
   317→  }
   318→}
