   322→function initResizer() {
   323→  resizer.addEventListener('mousedown', (e) => {
   324→    isResizing = true;
   325→    resizeStartX = e.clientX;
   326→    resizeStartEditorWidth = editorPane.offsetWidth;
   327→    resizeStartPreviewWidth = previewPane.offsetWidth;
   328→    document.body.classList.add('is-resizing');
   329→    e.preventDefault();
   330→  });
   331→
   332→  document.addEventListener('mousemove', (e) => {
   333→    if (!isResizing) return;
   334→
   335→    const dx = e.clientX - resizeStartX;
   336→    const containerWidth = resizeStartEditorWidth + resizeStartPreviewWidth;
   337→    const newEditorWidth = resizeStartEditorWidth + dx;
   338→    const minWidth = 200;
   339→
   340→    if (newEditorWidth < minWidth || containerWidth - newEditorWidth < minWidth) return;
   341→
   342→    const editorPercent = (newEditorWidth / containerWidth) * 100;
   343→    const previewPercent = 100 - editorPercent;
   344→
   345→    editorPane.style.flex = `0 0 ${editorPercent}%`;
   346→    previewPane.style.flex = `0 0 ${previewPercent}%`;
   347→  });
   348→
   349→  document.addEventListener('mouseup', () => {
   350→    if (!isResizing) return;
   351→    isResizing = false;
   352→    document.body.classList.remove('is-resizing');
   353→  });
   354→}
